}

Method.Source:
/// <summary>
/// This method initialize fields from table - CustInvoiceJour
/// </summary>
/// <param name = "_salesParmTable">VendInvoiceInfoTable _salesParmTable</param>
void initFromSalesParmTable(SalesParmTable _salesParmTable)
{
    next initFromSalesParmTable(_salesParmTable);

    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes && _salesParmTable.Ordering == DocumentStatus::Invoice)
    {
        this.ETGTERMONumber = _salesParmTable.ETGTERMONumber;
    }
    // Code added by Datta - 26/9/2024 - requirement from H011 - Start
    if(ETG_Parameters::find().ETGWaybilldetails == NoYes::Yes)
    {
        this.ETGWaybillNumber = _salesParmTable.ETGWaybillNumber;
        this.ETGWaybillDate = _salesParmTable.ETGWaybillDate;
        this.ETGLPONumber =_salesParmTable.ETGLPONumber;
        this.ETGLPODate = _salesParmTable.ETGLPODate;
        this.ETGVehicleNumber = _salesParmTable.ETGVehicleNumber;
    }
    // Code added by Datta - 26/9/2024 - requirement from H011 - End

    //NS,DLT, 29/05/2025, GMR report change for ACF update contract number for table custInvoiceJour
    if(ETGACFParameters::find().EnableGRMReportChanges == NoYes::Yes)
    {
        if(_salesParmTable.SalesId)
        {
            RefRecId agreementHeaderRecId = SalesTable::find(_salesParmTable.SalesId).MatchingAgreement;
            if(agreementHeaderRecId)
            {
                this.ETGContractNum = SalesAgreementHeader::find(agreementHeaderRecId).SalesNumberSequence;
            }
        }
    }
    //NS,DLT, 29/05/2025, GMR report change for ACF update contract number for table custInvoiceJour
}
